query:
UPDATE `users` SET `tenantId` = 1 WHERE `role` = 'admin';
UPDATE `rooms` SET `tenantId` = 1 WHERE `tenantId` = 1;
UPDATE `bookings` SET `tenantId` = 1 WHERE `tenantId` = 1;
UPDATE `credits` SET `tenantId` = 1 WHERE `tenantId` = 1;
UPDATE `payments` SET `tenantId` = 1 WHERE `tenantId` = 1;

INSERT INTO `professionalTenants` (`professionalId`, `tenantId`, `status`)
SELECT u.id, 1, 'approved' FROM `users` u 
WHERE u.role = 'professional' 
AND NOT EXISTS (
  SELECT 1 FROM `professionalTenants` pt WHERE pt.professionalId = u.id AND pt.tenantId = 1
);

